20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	const DEDUCTIBLE = 100;
26	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
27	const CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
28	
29	const COMPONENT_TYPES = ["rune", "moonstone"];
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const componentPremium = (type: string, count: number): number =>
34	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
35	
36	const itemSurcharge = (item: any): number => {
37	  const base = basePremiumForType(item.type);
38	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
39	    + (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
40	};
41	
42	const countByType = (items: any[]): Record<string, number> =>
43	  items.reduce((counts: Record<string, number>, item: any) => {
44	    counts[item.type] = (counts[item.type] ?? 0) + 1;
45	    return counts;
46	  }, {});
47	
48	const isComponent = (item: any): boolean => COMPONENT_TYPES.includes(item.type);
49	
50	const calculateQuotePremium = (items: any[], customer: any, stepIndex: number): number => {
51	  const regularItems = items.filter((item: any) => !isComponent(item));
52	  const components = items.filter(isComponent);
53	
54	  const regularBasePremium = regularItems.reduce(
55	    (sum, item) => sum + basePremiumForType(item.type), 0);
56	  const componentBasePremium = Object.entries(countByType(components)).reduce(
57	    (sum, [type, count]) => sum + componentPremium(type, count), 0);
58	  const policyBasePremium = regularBasePremium + componentBasePremium;
59	
60	  const totalSurcharges = regularItems.reduce(
61	    (sum, item) => sum + itemSurcharge(item), 0);
62	
63	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
64	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
65	    : 0;
66	  const followUpDiscount = stepIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
67	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
68	
69	  const premium = policyBasePremium + totalSurcharges - loyaltyDiscount
70	    + firstInsuranceSurcharge - followUpDiscount;
71	  return Math.ceil(premium + PROCESSING_FEE);
72	};
73	
74	const calculateClaimPayout = (damages: any[], policyItems: any[]): number =>
75	  damages.reduce((payout, damage) => {
76	    const policyItem = policyItems.find((item: any) => item.type === damage.type);
77	    const reimbursableAmount = policyItem && policyItem.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD
78	      ? damage.amount * CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE
79	      : damage.amount;
80	    return payout + Math.max(0, reimbursableAmount - DEDUCTIBLE);
81	  }, 0);
